// ─── Domain Types ────────────────────────────────────────────────────────────

export interface PaymentInput {
  amount: number;
  currency: string;
  cardToken: string;
  merchantId: string;
}

export interface PaymentResult {
  success: true;
  transaction_id: string;
}

export interface FraudCheckResult {
  flagged: boolean;
  reason?: string;
}

export interface GatewayResult {
  approved: boolean;
  transaction_id?: string;
  decline_reason?: string;
}

export interface FraudService {
  check(input: PaymentInput): Promise<FraudCheckResult>;
}

export interface PaymentGateway {
  charge(input: PaymentInput): Promise<GatewayResult>;
}

// ─── Payment Error ────────────────────────────────────────────────────────────

export type PaymentErrorCode =
  | "FRAUD_DETECTED"
  | "PAYMENT_DECLINED"
  | "FRAUD_SERVICE_UNAVAILABLE"
  | "GATEWAY_UNAVAILABLE";

export class PaymentError extends Error {
  readonly code: PaymentErrorCode;
  readonly cause?: unknown;

  constructor(code: PaymentErrorCode, message: string, cause?: unknown) {
    super(message);
    this.name = "PaymentError";
    this.code = code;
    this.cause = cause;
  }
}

// ─── Core Function ────────────────────────────────────────────────────────────

/**
 * Processes a payment by:
 *  1. Running a fraud check (throws FRAUD_DETECTED if flagged, FRAUD_SERVICE_UNAVAILABLE on network error)
 *  2. Charging the payment gateway (throws PAYMENT_DECLINED on decline, GATEWAY_UNAVAILABLE on network error)
 *  3. Returning { success: true, transaction_id } on approval
 *
 * The payment gateway is NEVER called when the fraud check flags or fails.
 */
export async function processPayment(
  input: PaymentInput,
  fraudService: FraudService,
  gateway: PaymentGateway
): Promise<PaymentResult> {
  // ── Step 1: Fraud check ───────────────────────────────────────────────────
  let fraudResult: FraudCheckResult;
  try {
    fraudResult = await fraudService.check(input);
  } catch (err) {
    throw new PaymentError(
      "FRAUD_SERVICE_UNAVAILABLE",
      "Fraud check service is unavailable",
      err
    );
  }

  if (fraudResult.flagged) {
    throw new PaymentError("FRAUD_DETECTED", "Payment flagged as fraudulent");
  }

  // ── Step 2: Charge gateway ────────────────────────────────────────────────
  let gatewayResult: GatewayResult;
  try {
    gatewayResult = await gateway.charge(input);
  } catch (err) {
    throw new PaymentError(
      "GATEWAY_UNAVAILABLE",
      "Payment gateway is unavailable",
      err
    );
  }

  if (!gatewayResult.approved) {
    throw new PaymentError(
      "PAYMENT_DECLINED",
      gatewayResult.decline_reason ?? "Payment declined"
    );
  }

  // ── Step 3: Return success ────────────────────────────────────────────────
  return {
    success: true,
    transaction_id: gatewayResult.transaction_id!,
  };
}

