import {
  processPayment,
  PaymentError,
  PaymentInput,
  FraudService,
  PaymentGateway,
} from "./processPayment";

// ─── Test Fixtures ────────────────────────────────────────────────────────────

const validInput: PaymentInput = {
  amount: 100_00,
  currency: "USD",
  cardToken: "tok_valid",
  merchantId: "merch_001",
};

function makeFraudService(override?: Partial<FraudService>): FraudService {
  return {
    check: jest.fn().mockResolvedValue({ flagged: false }),
    ...override,
  };
}

function makeGateway(override?: Partial<PaymentGateway>): PaymentGateway {
  return {
    charge: jest
      .fn()
      .mockResolvedValue({ approved: true, transaction_id: "txn_abc123" }),
    ...override,
  };
}

// ─── AC1: Happy path ──────────────────────────────────────────────────────────

describe("AC1 – valid input", () => {
  it("calls fraud check then gateway and returns { success: true, transaction_id }", async () => {
    const fraud = makeFraudService();
    const gateway = makeGateway();

    const result = await processPayment(validInput, fraud, gateway);

    // Fraud check called first
    expect(fraud.check).toHaveBeenCalledTimes(1);
    expect(fraud.check).toHaveBeenCalledWith(validInput);

    // Gateway called second
    expect(gateway.charge).toHaveBeenCalledTimes(1);
    expect(gateway.charge).toHaveBeenCalledWith(validInput);

    // Correct return shape
    expect(result).toEqual({ success: true, transaction_id: "txn_abc123" });
  });

  it("preserves the transaction_id returned by the gateway", async () => {
    const gateway = makeGateway({
      charge: jest
        .fn()
        .mockResolvedValue({ approved: true, transaction_id: "txn_xyz999" }),
    });

    const result = await processPayment(validInput, makeFraudService(), gateway);

    expect(result.transaction_id).toBe("txn_xyz999");
  });
});

// ─── AC2 + AC6: Fraud detected → gateway never called ────────────────────────

describe("AC2 + AC6 – fraud detected", () => {
  it("throws PaymentError with code FRAUD_DETECTED", async () => {
    const fraud = makeFraudService({
      check: jest.fn().mockResolvedValue({ flagged: true, reason: "stolen card" }),
    });
    const gateway = makeGateway();

    await expect(processPayment(validInput, fraud, gateway)).rejects.toMatchObject({
      code: "FRAUD_DETECTED",
    });
  });

  it("does NOT call the payment gateway when fraud is detected (AC6)", async () => {
    const fraud = makeFraudService({
      check: jest.fn().mockResolvedValue({ flagged: true }),
    });
    const gateway = makeGateway();

    await expect(processPayment(validInput, fraud, gateway)).rejects.toThrow(
      PaymentError
    );

    expect(gateway.charge).not.toHaveBeenCalled();
  });
});

// ─── AC3: Payment declined ────────────────────────────────────────────────────

describe("AC3 – payment gateway decline", () => {
  it("throws PaymentError with code PAYMENT_DECLINED", async () => {
    const gateway = makeGateway({
      charge: jest.fn().mockResolvedValue({
        approved: false,
        decline_reason: "Insufficient funds",
      }),
    });

    await expect(
      processPayment(validInput, makeFraudService(), gateway)
    ).rejects.toMatchObject({
      code: "PAYMENT_DECLINED",
    });
  });

  it("includes the decline reason from the gateway in the error message", async () => {
    const gateway = makeGateway({
      charge: jest.fn().mockResolvedValue({
        approved: false,
        decline_reason: "Card expired",
      }),
    });

    const error = await processPayment(validInput, makeFraudService(), gateway).catch(
      (e) => e
    );

    expect(error).toBeInstanceOf(PaymentError);
    expect(error.message).toBe("Card expired");
  });

  it("uses fallback message when gateway provides no decline_reason", async () => {
    const gateway = makeGateway({
      charge: jest.fn().mockResolvedValue({ approved: false }),
    });

    const error = await processPayment(validInput, makeFraudService(), gateway).catch(
      (e) => e
    );

    expect(error.code).toBe("PAYMENT_DECLINED");
    expect(error.message).toBeTruthy();
  });
});

// ─── AC4: Fraud service unavailable ──────────────────────────────────────────

describe("AC4 – fraud service network error", () => {
  it("throws PaymentError with code FRAUD_SERVICE_UNAVAILABLE", async () => {
    const networkError = new Error("ECONNREFUSED");
    const fraud = makeFraudService({
      check: jest.fn().mockRejectedValue(networkError),
    });

    await expect(
      processPayment(validInput, fraud, makeGateway())
    ).rejects.toMatchObject({
      code: "FRAUD_SERVICE_UNAVAILABLE",
    });
  });

  it("chains the original error as .cause", async () => {
    const networkError = new Error("ETIMEDOUT");
    const fraud = makeFraudService({
      check: jest.fn().mockRejectedValue(networkError),
    });

    const error: PaymentError = await processPayment(
      validInput,
      fraud,
      makeGateway()
    ).catch((e) => e);

    expect(error).toBeInstanceOf(PaymentError);
    expect(error.cause).toBe(networkError);
  });

  it("does NOT call the payment gateway when fraud service is unavailable", async () => {
    const fraud = makeFraudService({
      check: jest.fn().mockRejectedValue(new Error("network")),
    });
    const gateway = makeGateway();

    await expect(processPayment(validInput, fraud, gateway)).rejects.toThrow(
      PaymentError
    );

    expect(gateway.charge).not.toHaveBeenCalled();
  });
});

// ─── AC5: Gateway unavailable ─────────────────────────────────────────────────

describe("AC5 – payment gateway network error", () => {
  it("throws PaymentError with code GATEWAY_UNAVAILABLE", async () => {
    const networkError = new Error("ECONNREFUSED");
    const gateway = makeGateway({
      charge: jest.fn().mockRejectedValue(networkError),
    });

    await expect(
      processPayment(validInput, makeFraudService(), gateway)
    ).rejects.toMatchObject({
      code: "GATEWAY_UNAVAILABLE",
    });
  });

  it("chains the original error as .cause", async () => {
    const networkError = new Error("socket hang up");
    const gateway = makeGateway({
      charge: jest.fn().mockRejectedValue(networkError),
    });

    const error: PaymentError = await processPayment(
      validInput,
      makeFraudService(),
      gateway
    ).catch((e) => e);

    expect(error).toBeInstanceOf(PaymentError);
    expect(error.cause).toBe(networkError);
  });
});

// ─── Call order invariant ─────────────────────────────────────────────────────

describe("call ordering invariant", () => {
  it("always calls fraud check before gateway", async () => {
    const callOrder: string[] = [];
    const fraud: FraudService = {
      check: jest.fn().mockImplementation(async () => {
        callOrder.push("fraud");
        return { flagged: false };
      }),
    };
    const gateway: PaymentGateway = {
      charge: jest.fn().mockImplementation(async () => {
        callOrder.push("gateway");
        return { approved: true, transaction_id: "txn_order_test" };
      }),
    };

    await processPayment(validInput, fraud, gateway);

    expect(callOrder).toEqual(["fraud", "gateway"]);
  });
});

